mapper.select:
        select a.ts_code,b.name,b.industry_name_l1,b.industry_name_l2,b.industry_name_l3,b.index_code_l1,b.index_code_l2,b.index_code_l3,
               b.area,a.pct_chg,a.close,a.pre_close,a.high,a.low,a.open,a.pe_ttm,a.pb,a.ps_ttm,a.volume_ratio,a.total_mv/a.pb as asset,
               a.turnover_rate,a.amount,a.conti_up,b.market,a.total_mv,a.trade_date
        from common_daily.`${tradeDate}` as a
                 inner join stock_list.industry_member as b on a.ts_code = b.ts_code


                conti_up > 0


                conti_up > 1


                conti_up > 2


                conti_up > 3


                conti_up > 4



                order by total_mv desc;


                order by industry_name_l1, industry_name_l2, industry_name_l3, total_mv desc;


                order by asset desc;


                order by conti_up desc,industry_name_l1, industry_name_l2, industry_name_l3, total_mv desc;


                order by amount desc;



--         order by industry_name_l1, industry_name_l2, industry_name_l3, total_mv desc

select a.ts_code, a.trade_date, b.name, b.market, a.pb, a.total_mv, c.province, c.city, c.introduction, industry_name_l1, industry_name_l2, industry_name_l3 from common_daily.`${tradeDate}` as a inner join stock_list.industry_member as b on a.ts_code = b.ts_code left join stock_list.stock_company as c on b.ts_code = c.ts_code
a.pct_chg > 9
order by industry_name_l1,industry_name_l2, industry_name_l3, total_mv desc;

select a.ts_code, a.trade_date, b.name, b.market, a.pb, a.total_mv, c.province, c.city, c.main_business , c.business_scope , industry_name_l1, industry_name_l2, industry_name_l3 from common_daily.`${tradeDate}` as a inner join stock_list.industry_member as b on a.ts_code = b.ts_code left join stock_list.stock_company as c on b.ts_code = c.ts_code
a.pct_chg > 9
order by industry_name_l1,industry_name_l2, industry_name_l3, total_mv desc;

select a.ts_code ,a.ts_name,c.area,c.industry_name_l1,c.industry_name_l2 ,c.industry_name_l3,c.index_code_l1 ,c.index_code_l2 ,c.index_code_l3,b.amount,
       b.pct_chg,b.pe_ttm ,b.pb ,b.ps_ttm,a.buy_amount ,a.sell_amount ,a.net_amount ,a.hm_name ,a.hm_orgs ,c.market ,b.total_mv ,b.trade_date,b.conti_up,
       b.total_mv/b.pb as assets
from hot_money.`${tradeDate}` as a
         inner join common_daily.`${tradeDate}` as b on a.ts_code = b.ts_code
         inner join stock_list.industry_member as c on b.ts_code = c.ts_code

    order by industry_name_l1, total_mv desc;


    order by industry_name_l1, industry_name_l2, total_mv desc;


    order by industry_name_l1, industry_name_l2, industry_name_l3, total_mv desc;


    order by total_mv desc;


    order by assets desc;
